INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (1, 2, 130011, "ミッションねえ……\nちょうどいいや\nどこまで片付けられるか\n賭けをしようじゃないか", 2.1, 0.0, "2024/10/31 12:00:00", "ヤマト", "2030/01/01 14:59:59", 100, 3001, 3001100, -416.5);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (4, 2, 130011, "他人から言われた任務を\n言われるままにやるなんざ\n性に合わないんだがね……\nま、報酬は貰っとこうか", 5.68, 0.0, "2024/10/31 12:00:00", "ヤマト", "2030/01/01 14:59:59", 101, 3001, 3001101, -416.5);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (1, 1, 130011, "なんだい？　やれンなら\nとっとと済ませちまいな。\nフブキが早くやることやれ\nってボヤいてたよ。", 0.0, 0.0, "2024/10/31 12:00:00", "ヤマト", "2030/01/01 14:59:59", 102, 3001, 3001102, -416.5);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (1, 1, 130211, "え～？　ぼくに頼みごと～？\nどうしちゃおっかな～\nちゃんとお願いできたら\n考えてあげよっかな～？", 0.0, 0.0, "2024/10/31 12:00:00", "フブキ", "2030/01/01 14:59:59", 100, 3002, 3002100, -416.5);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (1, 1, 130211, "ほらほらぁ、これが\n欲しいんでしょ～？\nほんと、しょうがないよね～\nザコおに～いさん♡", 0.0, 0.0, "2024/10/31 12:00:00", "フブキ", "2030/01/01 14:59:59", 101, 3002, 3002101, -416.5);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (5, 2, 130211, "へえ～、欲しいんだ～？\nぼくのた・い・せ・つ・な・モ・ノ\nあははっ！　なに考えてんの？\nもうへんふしじゃ～んｗ", 8.53, 0.0, "2024/10/31 12:00:00", "フブキ", "2030/01/01 14:59:59", 102, 3002, 3002102, -416.5);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (7, 1, 130211, "なになに～？　もしかしてまた\nおねだりするつもりなんだ？\nとか言って、ほんとはぼくに\n会いたいだけだったりして～？", 5.67, 0.0, "2024/10/31 12:00:00", "フブキ", "2030/01/01 14:59:59", 103, 3002, 3002103, -416.5);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (1, 1, 130211, "ザコお兄さんってぇ\n頼み方もワンパなのぉ～？\nもっと必死にならないと\nぼくの心は動かせないよ～？", 0.0, 0.0, "2024/10/31 12:00:00", "フブキ", "2030/01/01 14:59:59", 104, 3002, 3002104, -416.5);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (3, 3, 130211, "あのさーザコお兄さん、\nな～んか調子乗ってない？\nぼくのこと、なんでもくれる\nチョロいやつとか思ってたりー？", 0.0, 0.0, "2024/10/31 12:00:00", "フブキ", "2030/01/01 14:59:59", 300, 3004, 3002300, -416.5);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (7, 7, 130211, "ざんね～ん♪\nうざいお兄さんには、もうな～んにもあげませ～ん♡\nほんとなっさけなーい♪\nばいば～い♡", 0.0, 0.0, "2024/10/31 12:00:00", "フブキ", "2030/01/01 14:59:59", 301, 3005, 3002400, -416.5);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (2, 1, 130211, "きゃはは、ほんと必死～♡\nは～、面白かった。\n笑えたからいいよ～\nそれ、恵んだげる～♪", 4.4, 0.0, "2024/10/31 12:00:00", "フブキ", "2030/01/01 14:59:59", 200, 3003, 3003200, -416.5);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (7, 7, 130211, "は～、しょうがないな～♡\nザコお兄さんってば\nほんとよわよわで\n情けないよね～ｗ", 0.0, 0.0, "2024/10/31 12:00:00", "フブキ", "2030/01/01 14:59:59", 201, 3003, 3003201, -416.5);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES (1, 2, 130211, "お兄さんってば、ぼくがいないと\nほんとザッコザコだよね～\nもっと感謝しろし～♪", 5.6, 0.0, "2024/10/31 12:00:00", "フブキ", "2030/01/01 14:59:59", 202, 3003, 3003202, -416.5);
